   309→### Error Handling Middleware
   310→
   311→```typescript
   312→// src/middleware/error-handler.ts
   313→import { HTTPException } from 'hono/http-exception';
   314→import { ZodError } from 'zod';
   315→
   316→export function errorHandler(err: Error, c: Context) {
   317→  console.error(err);
   318→
   319→  if (err instanceof ZodError) {
   320→    return c.json({
   321→      error: {
   322→        code: 'validation_error',
   323→        message: 'Validation failed',
   324→        details: err.flatten().fieldErrors
   325→      }
   326→    }, 400);
   327→  }
   328→
   329→  if (err instanceof HTTPException) {
   330→    return c.json({
   331→      error: {
   332→        code: err.message.toLowerCase().replace(/\s+/g, '_'),
   333→        message: err.message
   334→      }
   335→    }, err.status);
   336→  }
   337→
   338→  return c.json({
   339→    error: {
   340→      code: 'internal_error',
   341→      message: 'An unexpected error occurred'
   342→    }
   343→  }, 500);
   344→}
   345→```
