   347→## Webhooks
   348→
   349→### Webhook Registration
   350→
   351→```typescript
   352→// Webhook configuration
   353→interface WebhookConfig {
   354→  id: string;
   355→  url: string;
   356→  events: WebhookEvent[];
   357→  secret: string;
   358→  active: boolean;
   359→}
   360→
   361→type WebhookEvent =
   362→  | 'schedule.created'
   363→  | 'schedule.optimized'
   364→  | 'schedule.approved'
   365→  | 'event.scheduled'
   366→  | 'event.completed'
   367→  | 'drift.threshold_exceeded'
   368→  | 'asset.maintenance_due';
   369→
   370→// Webhook payload
   371→interface WebhookPayload {
   372→  id: string;
   373→  event: WebhookEvent;
   374→  timestamp: string;
   375→  data: unknown;
   376→}
   377→```
   378→
   379→### Webhook Delivery
   380→
   381→```typescript
   382→class WebhookService {
   383→  async deliver(event: WebhookEvent, data: unknown): Promise<void> {
   384→    const webhooks = await this.getActiveWebhooks(event);
   385→
   386→    for (const webhook of webhooks) {
   387→      await this.queue.add('webhook-delivery', {
