# API Design Patterns

This document covers API design for fleet maintenance scheduling, including REST endpoints, webhooks, and real-time subscriptions.

## API Architecture

```typescript
interface APIArchitecture {
  primary: 'REST with JSON';
  realtime: 'WebSocket or Server-Sent Events';
  integration: 'Webhooks for external systems';
  documentation: 'OpenAPI 3.1';
}
```

## REST API Design

### Resource Hierarchy

```
/api/v1
├── /assets
│   ├── GET     - List assets
│   ├── POST    - Create asset
│   └── /{id}
│       ├── GET     - Get asset
│       ├── PATCH   - Update asset
│       ├── DELETE  - Delete asset
│       └── /maintenance
│           └── GET - Asset maintenance config
├── /maintenance-types
│   ├── GET     - List types
│   └── /{id}   - CRUD
├── /schedules
│   ├── GET     - List schedules
│   ├── POST    - Create schedule
│   └── /{id}
│       ├── GET     - Get schedule
│       ├── PATCH   - Update schedule
│       ├── DELETE  - Delete schedule
│       ├── /events - Schedule events
│       ├── /optimize - Trigger optimization
│       └── /export  - Export schedule
└── /analytics
    ├── /drift      - Drift metrics
    ├── /workload   - Workload distribution
    └── /compliance - Maintenance compliance
```

### Endpoint Implementation

```typescript
// src/routes/assets.ts
import { Hono } from 'hono';
import { z } from 'zod';
import { zValidator } from '@hono/zod-validator';

const app = new Hono();

// List assets with filtering and pagination
const listAssetsQuery = z.object({
  page: z.coerce.number().min(1).default(1),
  limit: z.coerce.number().min(1).max(100).default(20),
  status: z.enum(['active', 'maintenance', 'retired']).optional(),
  assetType: z.string().optional(),
  search: z.string().optional()
});

app.get('/', zValidator('query', listAssetsQuery), async (c) => {
  const query = c.req.valid('query');

  const { assets, total } = await assetService.list({
    page: query.page,
    limit: query.limit,
    filters: {
      status: query.status,
      assetType: query.assetType,
      search: query.search
    }
  });

  return c.json({
    data: assets,
    pagination: {
      page: query.page,
      limit: query.limit,
      total,
      totalPages: Math.ceil(total / query.limit)
    }
  });
});

// Get single asset
app.get('/:id', async (c) => {
  const id = c.req.param('id');
  const asset = await assetService.getById(id);

  if (!asset) {
    return c.json({ error: 'Asset not found' }, 404);
  }

  return c.json({ data: asset });
});

// Create asset
const createAssetBody = z.object({
  name: z.string().min(1).max(255),
  assetType: z.string().min(1),
  externalId: z.string().optional(),
  currentMileage: z.number().min(0).default(0),
  manufacturer: z.string().optional(),
  model: z.string().optional()
});

app.post('/', zValidator('json', createAssetBody), async (c) => {
  const body = c.req.valid('json');

  const asset = await assetService.create(body);

  return c.json({ data: asset }, 201);
});

// Update asset
const updateAssetBody = createAssetBody.partial();

app.patch('/:id', zValidator('json', updateAssetBody), async (c) => {
  const id = c.req.param('id');
  const body = c.req.valid('json');

  const asset = await assetService.update(id, body);

  if (!asset) {
    return c.json({ error: 'Asset not found' }, 404);
  }

  return c.json({ data: asset });
});

export default app;
```

### Schedule Operations

```typescript
// src/routes/schedules.ts
import { Hono } from 'hono';

const app = new Hono();

// Create schedule and trigger optimization
const createScheduleBody = z.object({
  name: z.string().min(1),
  planningStartDate: z.string().date(),
  planningEndDate: z.string().date(),
  periodType: z.enum(['day', 'week', 'month']).default('week'),
  assetIds: z.array(z.string().uuid()).optional(), // Filter to specific assets
  options: z.object({
    solver: z.enum(['highs', 'cpsat', 'heuristic']).default('highs'),
    timeLimit: z.number().min(10).max(600).default(120),
    optimizationGoal: z.enum(['minimize_peak', 'minimize_variance']).default('minimize_peak')
  }).optional()
});

app.post('/', zValidator('json', createScheduleBody), async (c) => {
  const body = c.req.valid('json');
  const userId = c.get('userId');

  // Create schedule record
  const schedule = await scheduleService.create({
    ...body,
    createdBy: userId,
    status: 'pending'
  });

  // Queue optimization job
  await optimizationQueue.add('optimize-schedule', {
    scheduleId: schedule.id,
    options: body.options
  });

  return c.json({
    data: schedule,
    message: 'Schedule created. Optimization in progress.'
  }, 202);
});

// Get optimization status
app.get('/:id/status', async (c) => {
  const id = c.req.param('id');

  const schedule = await scheduleService.getById(id);
  if (!schedule) {
    return c.json({ error: 'Schedule not found' }, 404);
  }

  const job = await optimizationQueue.getJob(`optimize-${id}`);

  return c.json({
    data: {
      scheduleId: id,
      status: schedule.status,
      progress: job?.progress ?? null,
      solveTime: schedule.solveTimeSeconds,
      objectiveValue: schedule.objectiveValue
    }
  });
});

// Manually adjust event
const adjustEventBody = z.object({
  newPeriod: z.number().min(0),
  reason: z.string().min(1)
});

app.patch('/:scheduleId/events/:eventId', zValidator('json', adjustEventBody), async (c) => {
  const { scheduleId, eventId } = c.req.param();
  const body = c.req.valid('json');

  const event = await scheduleService.adjustEvent(
    scheduleId,
    eventId,
    body.newPeriod,
    body.reason
  );

  return c.json({ data: event });
});

// Export schedule
app.get('/:id/export', async (c) => {
  const id = c.req.param('id');
  const format = c.req.query('format') ?? 'json';

  const schedule = await scheduleService.getWithEvents(id);

  if (format === 'csv') {
    const csv = await exportService.toCSV(schedule);
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv',
        'Content-Disposition': `attachment; filename=schedule-${id}.csv`
      }
    });
  }

  return c.json({ data: schedule });
});

export default app;
```

## Response Formats

### Success Response

```typescript
interface SuccessResponse<T> {
  data: T;
  meta?: {
    generatedAt: string;
    version: string;
  };
}

interface PaginatedResponse<T> {
  data: T[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}
```

### Error Response

```typescript
interface ErrorResponse {
  error: {
    code: string;
    message: string;
    details?: Record<string, string[]>;  // Field-level errors
  };
}

// Error codes
const ErrorCodes = {
  VALIDATION_ERROR: 'validation_error',
  NOT_FOUND: 'not_found',
  CONFLICT: 'conflict',
  UNAUTHORIZED: 'unauthorized',
  FORBIDDEN: 'forbidden',
  INTERNAL_ERROR: 'internal_error'
} as const;
```

### Error Handling Middleware

```typescript
// src/middleware/error-handler.ts
import { HTTPException } from 'hono/http-exception';
import { ZodError } from 'zod';

export function errorHandler(err: Error, c: Context) {
  console.error(err);

  if (err instanceof ZodError) {
    return c.json({
      error: {
        code: 'validation_error',
        message: 'Validation failed',
        details: err.flatten().fieldErrors
      }
    }, 400);
  }

  if (err instanceof HTTPException) {
    return c.json({
      error: {
        code: err.message.toLowerCase().replace(/\s+/g, '_'),
        message: err.message
      }
    }, err.status);
  }

  return c.json({
    error: {
      code: 'internal_error',
      message: 'An unexpected error occurred'
    }
  }, 500);
}
```

## Webhooks

### Webhook Registration

```typescript
// Webhook configuration
interface WebhookConfig {
  id: string;
  url: string;
  events: WebhookEvent[];
  secret: string;
  active: boolean;
}

type WebhookEvent =
  | 'schedule.created'
  | 'schedule.optimized'
  | 'schedule.approved'
  | 'event.scheduled'
  | 'event.completed'
  | 'drift.threshold_exceeded'
  | 'asset.maintenance_due';

// Webhook payload
interface WebhookPayload {
  id: string;
  event: WebhookEvent;
  timestamp: string;
  data: unknown;
}
```

### Webhook Delivery

```typescript
class WebhookService {
  async deliver(event: WebhookEvent, data: unknown): Promise<void> {
    const webhooks = await this.getActiveWebhooks(event);

    for (const webhook of webhooks) {
      await this.queue.add('webhook-delivery', {
        webhookId: webhook.id,
        payload: {
          id: crypto.randomUUID(),
          event,
          timestamp: new Date().toISOString(),
          data
        }
      });
    }
  }

  async processDelivery(job: WebhookDeliveryJob): Promise<void> {
    const { webhookId, payload } = job.data;
    const webhook = await this.getWebhook(webhookId);

    const signature = this.sign(payload, webhook.secret);

    try {
      const response = await fetch(webhook.url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Webhook-Signature': signature,
          'X-Webhook-Id': payload.id
        },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(10000)
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }

      await this.recordSuccess(webhookId, payload.id);
    } catch (error) {
      await this.recordFailure(webhookId, payload.id, error);
      throw error; // Retry via queue
    }
  }

  private sign(payload: unknown, secret: string): string {
    const hmac = crypto.createHmac('sha256', secret);
    hmac.update(JSON.stringify(payload));
    return `sha256=${hmac.digest('hex')}`;
  }
}
```

## Real-Time Updates

### Server-Sent Events

```typescript
// src/routes/sse.ts
import { Hono } from 'hono';
import { streamSSE } from 'hono/streaming';

const app = new Hono();

app.get('/schedules/:id/updates', async (c) => {
  const scheduleId = c.req.param('id');

  return streamSSE(c, async (stream) => {
    // Subscribe to Redis pub/sub
    const subscriber = redis.duplicate();
    await subscriber.subscribe(`schedule:${scheduleId}:updates`);

    subscriber.on('message', async (channel, message) => {
      await stream.writeSSE({
        event: 'update',
        data: message
      });
    });

    // Send heartbeat every 30 seconds
    const heartbeat = setInterval(async () => {
      await stream.writeSSE({ event: 'heartbeat', data: '' });
    }, 30000);

    // Cleanup on disconnect
    stream.onAbort(() => {
      clearInterval(heartbeat);
      subscriber.unsubscribe();
      subscriber.quit();
    });
  });
});

export default app;
```

### WebSocket (Alternative)

```typescript
// src/ws/schedule-updates.ts
import { Hono } from 'hono';
import { upgradeWebSocket } from 'hono/bun';

const app = new Hono();

app.get('/ws/schedules/:id', upgradeWebSocket((c) => {
  const scheduleId = c.req.param('id');

  return {
    onOpen(event, ws) {
      console.log(`Client connected to schedule ${scheduleId}`);
      subscribeToUpdates(scheduleId, ws);
    },

    onMessage(event, ws) {
      // Handle client messages if needed
      const message = JSON.parse(event.data.toString());

      if (message.type === 'ping') {
        ws.send(JSON.stringify({ type: 'pong' }));
      }
    },

    onClose(event, ws) {
      unsubscribeFromUpdates(scheduleId, ws);
    }
  };
}));
```

