  step2_preparation: {
    action: 'Load assets, maintenance types, current state';
    source: 'PostgreSQL';
    output: 'Problem instance';
  };

  step3_optimization: {
    action: 'Solve scheduling problem';
    solver: 'HiGHS or CP-SAT via orchestrator';
    timeout: '60-300 seconds typical';
    output: 'Optimized schedule';
  };

  step4_validation: {
    action: 'Verify constraints satisfied';
    checks: ['Capacity', 'Time windows', 'Precedence'];
    output: 'Validated schedule or errors';
  };

  step5_persistence: {
    action: 'Store schedule and metrics';
    destination: 'PostgreSQL';
    sideEffects: ['Invalidate caches', 'Trigger notifications'];
